// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.nativerdf;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.common.transaction.QueryEvaluationMode;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * ORDER BY on a NativeStore must sort with the store's configured {@link QueryEvaluationMode}: extended (STANDARD)
 * comparison orders xsd:date against xsd:dateTime on the timeline, strict comparison falls back to the
 * datatype-precedence tie-breaker.
 */
public class NativeOrderByQueryEvaluationModeTest {

	private static final String QUERY = "PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>\n"
			+ "SELECT ?d WHERE { VALUES ?d { \"2022-06-15\"^^xsd:date \"2022-01-01T00:00:00Z\"^^xsd:dateTime } }\n"
			+ "ORDER BY ?d";

	@TempDir
	File dataDir;

	@Test
	public void standardModeSortsCrossTypeTemporalsOnTimeline() {
		assertThat(evaluate(QueryEvaluationMode.STANDARD))
				.containsExactly("2022-01-01T00:00:00Z", "2022-06-15");
	}

	@Test
	public void strictModeSortsCrossTypeTemporalsByDatatypePrecedence() {
		assertThat(evaluate(QueryEvaluationMode.STRICT))
				.containsExactly("2022-06-15", "2022-01-01T00:00:00Z");
	}

	private List<String> evaluate(QueryEvaluationMode mode) {
		NativeStore store = new NativeStore(new File(dataDir, mode.name()), "spoc");
		store.setDefaultQueryEvaluationMode(mode);
		SailRepository repository = new SailRepository(store);
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> rows = QueryResults.asList(conn.prepareTupleQuery(QUERY).evaluate());
			return rows.stream().map(bs -> bs.getValue("d").stringValue()).collect(Collectors.toList());
		} finally {
			repository.shutDown();
		}
	}
}
